import React from 'react';

const experiences = [
  {
    role: 'Full Stack Developer',
    company: 'Tech Innovations Ltd.',
    desc: 'Developing responsive web applications using React and Node.js. Working on ML integration projects to enhance user experience through predictive analytics and smart recommendations.',
    period: '2023 – Present'
  },
  {
    role: 'Frontend Developer',
    company: 'Digital Solutions Co.',
    desc: 'Built responsive user interfaces for various client projects. Specialized in React development and modern CSS frameworks, ensuring cross-browser compatibility and mobile-first design.',
    period: '2022 – 2023'
  },
  {
    role: 'Web Development Intern',
    company: 'StartupHub',
    desc: 'Gained hands-on experience in full-stack development. Contributed to multiple projects involving database design, API development, and frontend implementation using modern technologies.',
    period: '2021 – 2022'
  }
];

const Experience = () => {
  return (
    <section id="experience">
      <div className="exp-inner">
        <div className="reveal">
          <div className="section-label">
            <span className="section-label-line"></span>
            <span>Experience</span>
          </div>
          <h2 className="section-title">Where<br />I've<br /><em>worked</em></h2>
          <p style={{marginTop:'24px', color:'var(--muted)', fontSize:'0.9rem', lineHeight:'1.9', maxWidth:'280px'}}>
            Building responsive applications and exploring ML solutions. Each role has taught me something valuable about creating impactful software.
          </p>
        </div>

        <div className="exp-list reveal-stagger">
          {experiences.map((exp, index) => (
            <div key={index} className="exp-item">
              <div>
                <div className="exp-role">{exp.role}</div>
                <div className="exp-company">{exp.company}</div>
                <p className="exp-desc">{exp.desc}</p>
              </div>
              <div className="exp-period">{exp.period}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
